import React, { useState, useEffect } from 'react';

// Simple Login Component
const Login = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (email && password) {
      // Simple demo login - accepts any credentials for testing
      onLogin({ email, role: 'admin', name: 'Test User' });
    } else {
      setError('Please enter email and password');
    }
  };

  return (
    <div style={{ 
      minHeight: '100vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center',
      background: 'linear-gradient(135deg, #1e293b 0%, #0f172a 100%)'
    }}>
      <div style={{ 
        background: 'white', 
        padding: '40px', 
        borderRadius: '24px',
        width: '400px',
        boxShadow: '0 20px 40px rgba(0,0,0,0.2)'
      }}>
        <h1 style={{ marginBottom: '8px' }}>SCRAS</h1>
        <p style={{ color: '#64748b', marginBottom: '32px' }}>Campus Resource Allocation System</p>

        {error && <div style={{ color: 'red', marginBottom: '16px' }}>{error}</div>}

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: '20px' }}>
            <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600' }}>Email</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              style={{ width: '100%', padding: '12px', border: '1px solid #cbd5e1', borderRadius: '8px' }}
              placeholder="Enter your email"
            />
          </div>
          <div style={{ marginBottom: '20px' }}>
            <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600' }}>Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              style={{ width: '100%', padding: '12px', border: '1px solid #cbd5e1', borderRadius: '8px' }}
              placeholder="Enter your password"
            />
          </div>
          <button 
            type="submit" 
            style={{ 
              width: '100%', 
              padding: '14px', 
              background: '#3b82f6', 
              color: 'white', 
              border: 'none', 
              borderRadius: '8px',
              fontSize: '16px',
              fontWeight: '600',
              cursor: 'pointer'
            }}
          >
            Login
          </button>
        </form>
      </div>
    </div>
  );
};

// Simple Dashboard
const Dashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState('departments');

  const menuItems = [
    { id: 'departments', label: 'Departments', icon: '🏛️' },
    { id: 'teachers', label: 'Teachers', icon: '👨‍🏫' },
    { id: 'students', label: 'Students', icon: '👨‍🎓' },
    { id: 'rooms', label: 'Rooms', icon: '🚪' },
    { id: 'courses', label: 'Courses', icon: '📚' },
  ];

  return (
    <div style={{ display: 'flex', minHeight: '100vh' }}>
      {/* Sidebar */}
      <div style={{ 
        width: '280px', 
        background: '#1e293b', 
        color: 'white',
        position: 'fixed',
        height: '100vh',
        display: 'flex',
        flexDirection: 'column'
      }}>
        <div style={{ padding: '24px 20px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
          <h2>SCRAS</h2>
          <span style={{ fontSize: '12px', color: '#64748b' }}>Administrator</span>
        </div>

        <nav style={{ flex: 1, padding: '20px 16px' }}>
          {menuItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '12px',
                width: '100%',
                padding: '12px 16px',
                marginBottom: '4px',
                background: activeTab === item.id ? '#3b82f6' : 'transparent',
                border: 'none',
                borderRadius: '8px',
                color: activeTab === item.id ? 'white' : '#cbd5e1',
                cursor: 'pointer',
                fontSize: '14px',
                textAlign: 'left'
              }}
            >
              <span>{item.icon}</span>
              <span>{item.label}</span>
            </button>
          ))}
        </nav>

        <div style={{ padding: '20px', borderTop: '1px solid rgba(255,255,255,0.1)' }}>
          <div style={{ fontSize: '14px', fontWeight: '600' }}>{user?.name || 'Admin User'}</div>
          <div style={{ fontSize: '12px', color: '#64748b' }}>{user?.email || 'admin@scras.edu'}</div>
          <button 
            onClick={onLogout}
            style={{
              marginTop: '12px',
              width: '100%',
              padding: '8px',
              background: '#ef4444',
              color: 'white',
              border: 'none',
              borderRadius: '6px',
              cursor: 'pointer'
            }}
          >
            Logout
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div style={{ marginLeft: '280px', flex: 1 }}>
        <div style={{ 
          background: 'white', 
          padding: '16px 32px', 
          borderBottom: '1px solid #e2e8f0',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <span>Welcome, {user?.name || 'Admin'}!</span>
        </div>

        <div style={{ padding: '32px' }}>
          <div style={{ 
            background: 'white', 
            borderRadius: '16px', 
            padding: '24px',
            border: '1px solid #e2e8f0'
          }}>
            <h1>{activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}</h1>
            <p style={{ color: '#64748b', marginTop: '8px' }}>Content for {activeTab} will appear here once connected to backend.</p>

            {/* Sample data display */}
            <div style={{ marginTop: '24px' }}>
              <h3>Sample Data (from backend when connected)</h3>
              <pre style={{ 
                background: '#f1f5f9', 
                padding: '16px', 
                borderRadius: '8px',
                marginTop: '12px'
              }}>
                {`Try logging in with:
- Admin: admin@resora.com / 12345678
- Student: 24l0601@lhr.nu.edu.pk / 12345678
- Teacher: hina.i@university.edu / 12345678`}
              </pre>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

// Main App
const App = () => {
  const [authenticated, setAuthenticated] = useState(false);
  const [user, setUser] = useState(null);

  // Check for existing session on load
  useEffect(() => {
    const savedUser = localStorage.getItem('demo_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      setAuthenticated(true);
    }
  }, []);

  const handleLogin = (userData) => {
    setUser(userData);
    setAuthenticated(true);
    localStorage.setItem('demo_user', JSON.stringify(userData));
  };

  const handleLogout = () => {
    setAuthenticated(false);
    setUser(null);
    localStorage.removeItem('demo_user');
  };

  if (!authenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return <Dashboard user={user} onLogout={handleLogout} />;
};

export default App;
